        document.getElementById('reviewer-notes')?.focus();
    } else if (e.key === ' ' || e.key === ']') {
        e.preventDefault();
        document.getElementById('btn-next')?.click();
    }
});

// Scroll detail panel to top when navigating to a new finding
document.addEventListener('htmx:afterSwap', function(e) {
    if (e.detail.target?.id === 'detail-panel') {
        const trigger = e.detail.elt;
        const isReviewBtn = trigger?.id === 'btn-reviewed' || trigger?.id === 'btn-false-positive';
        if (!isReviewBtn) {
            document.getElementById('detail-panel').scrollTop = 0;
        }
    }
});

// After ANY htmx settle, sync the active row to match the detail panel.
// Uses afterSettle (not afterRequest) because content must be in the DOM.
// Handles: row clicks, next-unreviewed, review buttons, save notes,
// filter changes, and keyboard navigation.
document.addEventListener('htmx:afterSettle', function() {
    const detail = document.querySelector('#detail-panel article[data-finding-id]');
    const activeId = detail?.dataset.findingId;
    const currentActive = document.querySelector('.finding-row.active');
    // Skip if already correct (avoid unnecessary DOM churn)
    if (currentActive?.id === 'finding-row-' + activeId) return;
    document.querySelectorAll('.finding-row.active').forEach(r => r.classList.remove('active'));
    if (activeId) {
        const row = document.getElementById('finding-row-' + activeId);
        if (row) {
            row.classList.add('active');
            row.scrollIntoView({block: 'nearest'});
        }
    }
});
</script>
